-- =====================================================================
-- 0006_seed_engine_rules.sql  ·  ÜRETİLMİŞ DOSYA — elle düzenleme.
-- Üretici: scripts/generate-engine-seed.mjs  (yeniden üret: npm run engine:generate)
--
-- İçerik: 40 gökyüzü kuralı (engine-rules-katman1a.json=12 · engine-rules-katman1b.json=10 · engine-rules-katman2.json=18).
-- Idempotent: ON CONFLICT (rule_id) DO UPDATE (panelde tekrar çalıştırılabilir).
-- ÖN KOŞUL: 0005_retrieval.sql UYGULANMIŞ olmalı (aspect_quality/natal_target
--           NOT NULL kaldırılmış) — yoksa katman-1a satırları eklenemez.
--
-- Not (A1 kararı): source_chunk_refs hepsi boş; provenance köprüsü (kabul #6)
-- refine fazına ertelendi — engine eşleştirmesi ilişkisel/RAG-dışı.
-- =====================================================================

insert into public.engine_rules (
  rule_id, transit_planet, aspect_quality, natal_target,
  sign_modifier, house_modifier, theme_internal, user_text_variants,
  body_zone, herb_motif, evidence_label, priority, source_chunk_refs
)
select
  e->>'rule_id',
  e->>'transit_planet',
  e->>'aspect_quality',
  e->>'natal_target',
  e->>'sign_modifier',
  e->>'house_modifier',
  e->>'theme_internal',
  coalesce(e->'user_text_variants', '[]'::jsonb),
  e->>'body_zone',
  e->>'herb_motif',
  e->>'evidence_label',
  (e->>'priority')::int,
  coalesce(e->'source_chunk_refs', '[]'::jsonb)
from jsonb_array_elements($weng$[{"rule_id":"k1a_ay_koc","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"koc","house_modifier":null,"theme_internal":"baslangic_enerji","user_text_variants":["Ay bugün Koç'ta — bir şeye başlamak için bahane aramaya gerek yok. En küçük ilk adım bile bugünün ruhuna uyar.","Koç Ay'ı sabırsız değil, taze demektir. Bugün enerjini tek bir işe yöneltmek, ona dağıtmaktan iyi gelebilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_boga","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"boga","house_modifier":null,"theme_internal":"yavaslik_duyular","user_text_variants":["Ay bugün Boğa'da — acele etmeyen bir gün. Duyularına, yavaş bir kahvaltıya, dokunduğun şeylerin dokusuna alan açabilirsin.","Boğa Ay'ı köklenmeyi sever. Bugün az ama sağlam; telaş yerine tat almak gündemde olabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_ikizler","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"ikizler","house_modifier":null,"theme_internal":"merak_iletisim","user_text_variants":["Ay bugün İkizler'de — zihnin hafif ve meraklı olabilir. Kısa sohbetler, notlar, küçük sorular güne iyi oturur.","İkizler Ay'ında dağınıklık kusur değil, tarama biçimidir. Bugün derin dalış yerine geniş bakış işe yarayabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_yengec","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"yengec","house_modifier":null,"theme_internal":"ic_dunya_bakim","user_text_variants":["Ay bugün kendi burcu Yengeç'te — iç dünyana ve sana iyi gelen alışkanlıklara alan açabilirsin. Büyük kararlardan çok küçük bakımların günü.","Yengeç Ay'ı eve dönmek gibidir. Bugün kendine bir yuva hissi kurmak — bir köşe, bir fincan, bir sessizlik — yeterli olabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_aslan","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"aslan","house_modifier":null,"theme_internal":"gorunurluk_oyun","user_text_variants":["Ay bugün Aslan'da — biraz görünmek, biraz oynamak iyi gelebilir. Yaptığın şeyi saklamak zorunda değilsin.","Aslan Ay'ı içindeki çocuğa alan ister. Bugün ciddi işlerin arasına küçük bir keyif sıkıştırmak günü yumuşatabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_basak","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"basak","house_modifier":null,"theme_internal":"duzen_kucuk_isler","user_text_variants":["Ay bugün Başak'ta — küçük düzenlemelerin günü. Tek bir çekmece, tek bir liste; hepsi bu kadar.","Başak Ay'ı mükemmellik değil, özen demektir. Bugün bir şeyi 'yeterince iyi' bırakabilmek de bir beceri."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_terazi","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"terazi","house_modifier":null,"theme_internal":"denge_iliski","user_text_variants":["Ay bugün Terazi'de — dengeye ve ilişkilere dikkat kayabilir. Bir konuşmayı yumuşatmak için uygun bir gün olabilir.","Terazi Ay'ında karar zorlaşabilir; sorun değil. Bugün tartmak da bir ilerleme biçimi."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_akrep","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"akrep","house_modifier":null,"theme_internal":"derinlik_donusum","user_text_variants":["Ay bugün Akrep'te — yüzeyde kalmak zor olabilir. Derinde ne olduğuna nazikçe bakmak için uygun bir gün; acele cevap gerekmiyor.","Akrep Ay'ı yoğunluğu büyütebilir. Duygu güçlüyse, onu hemen çözmek yerine sadece adlandırmak bugün yeterli olabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_yay","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"yay","house_modifier":null,"theme_internal":"genisleme_anlam","user_text_variants":["Ay bugün Yay'da — ufuk açık. Küçük bir plan, yeni bir fikir ya da uzaktaki bir hayale bakmak güne iyi gelebilir.","Yay Ay'ı 'neden' sorusunu sever. Bugün yaptığın işin anlamını hatırlamak, işin kendisini de hafifletebilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_oglak","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"oglak","house_modifier":null,"theme_internal":"yapi_sorumluluk","user_text_variants":["Ay bugün Oğlak'ta — yapı kurmanın günü. Bir işi bitirmek, bir sınırı netleştirmek bugün doğal akar.","Bugün küçük ve sağlam bir adım, büyük plandan daha değerli olabilir. Oğlak Ay'ı yapı kurmayı sever."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_kova","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"kova","house_modifier":null,"theme_internal":"yenilik_topluluk","user_text_variants":["Ay bugün Kova'da — alışılmışın biraz dışına çıkmak iyi gelebilir. Farklı bir yol, farklı bir fikir; denemesi serbest.","Kova Ay'ı mesafeden bakmayı bilir. Bugün bir konuya kuşbakışı bakmak, içinde boğulmaktan iyi olabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1a_ay_balik","transit_planet":"ay","aspect_quality":null,"natal_target":null,"sign_modifier":"balik","house_modifier":null,"theme_internal":"sezgi_akis","user_text_variants":["Ay bugün Balık'ta — sınırlar yumuşayabilir, sezgi öne çıkabilir. Programı biraz gevşetmek güne uyum sağlar.","Balık Ay'ında netlik beklemek yorucu olabilir. Bugün akışa küçük bir alan bırakmak yeterli."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":10,"source_chunk_refs":[]},{"rule_id":"k1b_ay_sert_gunes","transit_planet":"ay","aspect_quality":"sert","natal_target":"gunes","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_sert_gunes","user_text_variants":["Ay bugün Güneş'inle gergin bir açıda — iç ihtiyaçlarla günün talepleri çekişebilir. İkisini de duymak, birini bastırmaktan iyi gelir.","Bugün duyguyla irade aynı yöne bakmayabilir. Küçük bir uzlaşma — kısa bir mola, sonra iş — günü yumuşatabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k1b_ay_yum_gunes","transit_planet":"ay","aspect_quality":"yumusak","natal_target":"gunes","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_yumusak_gunes","user_text_variants":["Ay bugün Güneş'ini destekliyor — içinle dışın aynı hizada. Kendin gibi davranmak bugün zahmetsiz olabilir.","Duygu ve niyet bugün el ele. Ertelediğin kişisel bir şeye alan açmak için akışkan bir gün."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k1b_ay_sert_ay","transit_planet":"ay","aspect_quality":"sert","natal_target":"ay","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_sert_ay","user_text_variants":["Gökteki Ay bugün doğum Ay'ınla çekişiyor — duygular sebepsiz dalgalanabilir. Dalganın geçmesine izin vermek, onunla boğuşmaktan kolay olabilir.","Bugün hassasiyet yüzeye yakın. Kendine küçük bir yumuşaklık payı bırakmak iyi gelir; her hissi çözmek gerekmiyor."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k1b_ay_yum_ay","transit_planet":"ay","aspect_quality":"yumusak","natal_target":"ay","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_yumusak_ay","user_text_variants":["Gökteki Ay doğum Ay'ınla uyumlu — duygusal zemin bugün sakin. İçine iyi gelen ne varsa, bugün kolay bulunur.","Bugün iç sular durgun. Dinlenmek, beslenmek, sevdiğin küçük ritüeller: hepsi yerine oturuyor."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k1b_ay_sert_asc","transit_planet":"ay","aspect_quality":"sert","natal_target":"asc","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_sert_asc","user_text_variants":["Ay bugün yükselenini zorluyor — içeride hissettiğinle dışarı yansıyan uyuşmayabilir. Maskeyi zorlamak yerine biraz sadelik iyi gelebilir.","Bugün 'nasıl görünüyorum' sorusu yorabilir. Cevabı basitleştirmek serbest: bugünlük, olduğun kadarı yeter."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k1b_ay_yum_asc","transit_planet":"ay","aspect_quality":"yumusak","natal_target":"asc","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_yumusak_asc","user_text_variants":["Ay bugün yükselenine eşlik ediyor — kendini ifade etmek doğal akabilir. İnsanlarla temas bugün az enerji ister.","Bugün dışa dönük yüzünle için barışık. Küçük bir buluşma ya da kısa bir paylaşım güne iyi oturabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k1b_ay_sert_merkur","transit_planet":"ay","aspect_quality":"sert","natal_target":"merkur","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_sert_merkur","user_text_variants":["Ay bugün Merkür'ünle gergin — duygu, kelimelerin arasına karışabilir. Önemli mesajları göndermeden bir kez daha okumak yeterli.","Bugün zihin ile kalp farklı dilde konuşabilir. Yazıp beklemek, söyleyip düzeltmekten kolay olabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k1b_ay_yum_merkur","transit_planet":"ay","aspect_quality":"yumusak","natal_target":"merkur","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_yumusak_merkur","user_text_variants":["Ay bugün Merkür'ünü destekliyor — hisleri kelimeye dökmek kolaylaşıyor. Günlüğün ya da ertelenen bir mesaj için akışkan bir gün.","Bugün iç ses net. Aklındaki bir konuyu konuşmak ya da yazmak, taşımaktan hafif gelebilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k1b_ay_sert_venus","transit_planet":"ay","aspect_quality":"sert","natal_target":"venus","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_sert_venus","user_text_variants":["Ay bugün Venüs'ünle çekişiyor — keyif ve sorumluluk aynı anda çağırabilir. Küçük bir güzelliğe de yer açmak dengeyi kurar.","Bugün gönül ister, gün izin vermez gibi hissedilebilir. Minik bir keyfi araya sıkıştırmak iyi gelebilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k1b_ay_yum_venus","transit_planet":"ay","aspect_quality":"yumusak","natal_target":"venus","sign_modifier":null,"house_modifier":null,"theme_internal":"ay_yumusak_venus","user_text_variants":["Ay bugün Venüs'ünü destekliyor — güzellik, tat ve yakınlık bugün kolay bulunur. Kendine nazik bir şey seçmek serbest.","Bugün küçük keyiflerin günü: sevdiğin bir koku, bir çay, kısa bir sohbet. Az şey, çok iyi gelebilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":20,"source_chunk_refs":[]},{"rule_id":"k2_saturn_sert_gunes","transit_planet":"saturn","aspect_quality":"sert","natal_target":"gunes","sign_modifier":null,"house_modifier":null,"theme_internal":"saturn_sert_gunes","user_text_variants":["Satürn bu dönem Güneş'inle zorlayıcı bir açıda — enerji kısıtlı, sorumluluk belirgin hissedilebilir. Bu bir eksiklik değil; az ama sağlam adım kurma daveti.","Bu dönem her şey biraz ağır akıyorsa, dönem 'neyi gerçekten taşımak istiyorum' sorusunu büyütüyor olabilir. Cevap sadeleştirir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_saturn_sert_ay","transit_planet":"saturn","aspect_quality":"sert","natal_target":"ay","sign_modifier":null,"house_modifier":null,"theme_internal":"saturn_sert_ay","user_text_variants":["Satürn bu dönem Ay'ını sıkıştırabilir — duygular kısılmış, içe çekilme artmış olabilir. İhtiyacını küçümsememek önemli; destek istemek de olgunluğun parçası.","Bu dönem içsel hava serin olabilir. Sıcak tutan küçük rutinler kurmak iyi gelir; mevsimler geçicidir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_saturn_sert_asc","transit_planet":"saturn","aspect_quality":"sert","natal_target":"asc","sign_modifier":null,"house_modifier":null,"theme_internal":"saturn_sert_asc","user_text_variants":["Satürn bu dönem yükselenine yaslanıyor — sorumluluklar görünür, oyun alanı dar hissedilebilir. Sınır çizmek bu dönemin doğal ödevi olabilir.","Bu dönem 'hayır' demeyi öğreten dönemlerden olabilir. Her hayır, gerçek bir evete alan açar."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_saturn_yum_gunes","transit_planet":"saturn","aspect_quality":"yumusak","natal_target":"gunes","sign_modifier":null,"house_modifier":null,"theme_internal":"saturn_yumusak_gunes","user_text_variants":["Satürn bu dönem Güneş'ini destekliyor — emek karşılık buluyor, yapı kurmak kolaylaşıyor. Uzun vadeli bir işe temel atmak için sağlam bir dönem.","Bu dönem disiplin zorlama değil, doğal ritim gibi gelebilir. Küçük düzenli adımlar sessizce birikiyor."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_saturn_yum_ay","transit_planet":"saturn","aspect_quality":"yumusak","natal_target":"ay","sign_modifier":null,"house_modifier":null,"theme_internal":"saturn_yumusak_ay","user_text_variants":["Satürn bu dönem Ay'ına sakin bir zemin veriyor — duygusal istikrar kurmak kolaylaşıyor. İyi gelen rutinleri kalıcılaştırma dönemi.","Bu dönem iç dünya sağlam zeminde. Bir alışkanlığı kökleştirmek için uygun bir hava var."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_saturn_yum_asc","transit_planet":"saturn","aspect_quality":"yumusak","natal_target":"asc","sign_modifier":null,"house_modifier":null,"theme_internal":"saturn_yumusak_asc","user_text_variants":["Satürn bu dönem yükselenini destekliyor — duruş netleşiyor, güven veren bir olgunluk yansıyor olabilir. Uzun vadeli bir söz için uygun zemin.","Bu dönem 'kim olduğun' sorusu sadeleşiyor olabilir. Az söz, net duruş dönemi."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_jupiter_sert_gunes","transit_planet":"jupiter","aspect_quality":"sert","natal_target":"gunes","sign_modifier":null,"house_modifier":null,"theme_internal":"jupiter_sert_gunes","user_text_variants":["Jüpiter bu dönem Güneş'inle gergin — iştah büyüyor, abartı çekici gelebilir. Büyümek güzel; ölçüyü koyan yine sensin.","Bu dönem 'daha fazlası' sesi yüksek olabilir. Genişlemeden önce sormak iyi gelir: neye evet diyorum, neden?"],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_jupiter_sert_ay","transit_planet":"jupiter","aspect_quality":"sert","natal_target":"ay","sign_modifier":null,"house_modifier":null,"theme_internal":"jupiter_sert_ay","user_text_variants":["Jüpiter bu dönem Ay'ını büyütebilir — duygular geniş, tepkiler bol gelebilir. Cömertlik güzel; taşma sınırını belirlemek sende.","Bu dönem hisler geniş ekranda oynayabilir. Büyük duygu, büyük karar gerektirmez."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_jupiter_sert_asc","transit_planet":"jupiter","aspect_quality":"sert","natal_target":"asc","sign_modifier":null,"house_modifier":null,"theme_internal":"jupiter_sert_asc","user_text_variants":["Jüpiter bu dönem yükseleninle çekişiyor — vaat etmek kolay, yetişmek zor olabilir. Sözü küçük tutup yapmak, sonra büyütmek iyi bir sıra.","Bu dönem görünürlük artabilir ama dağınık büyüme yorar. Tek alan seçip orada genişlemek daha iyi gelebilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_jupiter_yum_gunes","transit_planet":"jupiter","aspect_quality":"yumusak","natal_target":"gunes","sign_modifier":null,"house_modifier":null,"theme_internal":"jupiter_yumusak_gunes","user_text_variants":["Jüpiter bu dönem Güneş'ini büyütüyor — fırsatlar, iyimserlik ve alan genişliyor olabilir. Kapıyı çalmak için iyi bir dönem.","Bu dönem rüzgâr arkandan esiyor olabilir. Bir adım büyüğünü denemek için doğal bir destek var."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_jupiter_yum_ay","transit_planet":"jupiter","aspect_quality":"yumusak","natal_target":"ay","sign_modifier":null,"house_modifier":null,"theme_internal":"jupiter_yumusak_ay","user_text_variants":["Jüpiter bu dönem Ay'ını besliyor — iç dünya cömert, şükran kolay. İyi hissettiren şeyleri çoğaltma dönemi olabilir.","Bu dönem duygusal bir bereket havası olabilir; paylaştıkça büyüyen türden."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_jupiter_yum_asc","transit_planet":"jupiter","aspect_quality":"yumusak","natal_target":"asc","sign_modifier":null,"house_modifier":null,"theme_internal":"jupiter_yumusak_asc","user_text_variants":["Jüpiter bu dönem yükselenini parlatıyor — insanların sana yaklaşması kolaylaşabilir, kapılar aralanabilir. Görünür olmak bu dönem daha az enerji ister.","Bu dönem temas bereketli: yeni insanlar, yeni alanlar. Davetlere açık kalmak iyi gelebilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_mars_sert_gunes","transit_planet":"mars","aspect_quality":"sert","natal_target":"gunes","sign_modifier":null,"house_modifier":null,"theme_internal":"mars_sert_gunes","user_text_variants":["Mars bu dönem Güneş'inle sürtüşüyor — sabırsızlık ve kıvılcım artabilir. Enerjiyi kavgaya değil harekete yatırmak dönemi hafifletir.","Bu dönem fitil kısa olabilir. Tepkiden önce bir nefes; sonra istersen yine söylersin."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_mars_sert_ay","transit_planet":"mars","aspect_quality":"sert","natal_target":"ay","sign_modifier":null,"house_modifier":null,"theme_internal":"mars_sert_ay","user_text_variants":["Mars bu dönem Ay'ını dürtüyor — duygular çabuk alevlenebilir. Bedeni yormak zihni yatıştırır; yürüyüş iyi bir supap olabilir.","Bu dönem içeride kaynama olabilir. Duyguyu bastırmak yerine ona hareketle çıkış vermek iyi gelir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_mars_sert_asc","transit_planet":"mars","aspect_quality":"sert","natal_target":"asc","sign_modifier":null,"house_modifier":null,"theme_internal":"mars_sert_asc","user_text_variants":["Mars bu dönem yükselenini kışkırtıyor — girişkenlik artar, sivrilik de artabilir. Cesaret güzel; tonu ayarlamak sende.","Bu dönem 'hemen şimdi' hissi güçlü olabilir. Gerçek aciliyeti histen ayırmak günü sadeleştirir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_mars_yum_gunes","transit_planet":"mars","aspect_quality":"yumusak","natal_target":"gunes","sign_modifier":null,"house_modifier":null,"theme_internal":"mars_yumusak_gunes","user_text_variants":["Mars bu dönem Güneş'ine güç veriyor — enerji, odak ve cesaret elinin altında olabilir. Fiziksel bir hedef için verimli dönem.","Bu dönem motor sende. Başlatmakta zorlandığın işe şimdi omuz vermek kolaylaşır."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_mars_yum_ay","transit_planet":"mars","aspect_quality":"yumusak","natal_target":"ay","sign_modifier":null,"house_modifier":null,"theme_internal":"mars_yumusak_ay","user_text_variants":["Mars bu dönem Ay'ını canlandırıyor — duygusal cesaret artıyor; içini söylemek kolaylaşabilir. Bedenin de söz ister: hareket iyi gelir.","Bu dönem his ile eylem barışık. 'Canım istiyor'u küçümsememek, onu sağlıklı bir harekete çevirmek yeterli."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]},{"rule_id":"k2_mars_yum_asc","transit_planet":"mars","aspect_quality":"yumusak","natal_target":"asc","sign_modifier":null,"house_modifier":null,"theme_internal":"mars_yumusak_asc","user_text_variants":["Mars bu dönem yükselenine ivme veriyor — girişkenlik doğal akıyor olabilir. İlk adımı atmak için zemin uygun.","Bu dönem duruşta diri bir enerji var. Sporun, yürüyüşün, dik duruşun dönemi olabilir."],"body_zone":null,"herb_motif":null,"evidence_label":"sembolik","priority":30,"source_chunk_refs":[]}]$weng$::jsonb) as e
